// js/ui/renderers/calorieHeatmapRenderer.js
// Visual calendar with color-coded calorie adherence

import { StateManager } from '../../core/stateManager.js';
import * as Selectors from '../../core/selectors.js';
import { explainOutlier } from '../../core/outlierExplainer.js';
import { setAnalysisRangeAndSyncChart } from '../../interactions/chartRangeHelper.js';
import { bindCrossWidgetHoverDate } from '../../interactions/crossWidgetHoverLink.js';

/**
 * Calorie Heatmap Calendar:
 * - Color-coded days based on calorie target adherence
 * - Click to see day details
 * - Monthly view
 */
export const CalorieHeatmapRenderer = {
    _container: null,
    _currentMonth: null,
    _currentYear: null,
    _targetCalories: 2000, // Default, will be calculated

    init() {
        this._container = document.getElementById('calorie-heatmap-content');
        if (!this._container) {
            console.warn('[CalorieHeatmapRenderer] Container not found.');
            return;
        }

        const now = new Date();
        this._currentMonth = now.getMonth();
        this._currentYear = now.getFullYear();

        StateManager.subscribeToSpecificEvent('state:displayStatsUpdated', () => this._render());
        StateManager.subscribeToSpecificEvent('state:filteredDataChanged', () => this._render());
        StateManager.subscribeToSpecificEvent('state:initializationComplete', () => this._render());

        const s = StateManager.getState();
        if (s.isInitialized) this._render();
    },

    _render() {
        const state = StateManager.getState();
        const processedData = Selectors.selectProcessedData(state);
        const displayStats = state.displayStats || {};

        if (!processedData || processedData.length < 7) {
            this._renderNoData();
            return;
        }

        // Calculate target from adaptive TDEE or average
        this._targetCalories = displayStats.adaptiveTDEE || displayStats.avgTDEE ||
            this._calculateAverageCalories(processedData);

        const calendarData = this._buildCalendarData(processedData);
        this._renderCalendar(calendarData);
    },

    _calculateAverageCalories(data) {
        const withCalories = data.filter(d => d.calorieIntake != null);
        if (withCalories.length === 0) return 2000;
        return withCalories.reduce((s, d) => s + d.calorieIntake, 0) / withCalories.length;
    },

    _buildCalendarData(data) {
        // Build a map of date -> data
        // When duplicate date entries exist (e.g. from "2026-01-02" and "2026-1-2" in data.json),
        // prefer the entry with more relevant data (calorieIntake, weight value).
        const dataMap = {};
        data.forEach(d => {
            if (!(d.date instanceof Date) || isNaN(d.date.getTime())) {
                return; // Skip invalid dates
            }
            const key = `${d.date.getFullYear()}-${d.date.getMonth()}-${d.date.getDate()}`;
            const existing = dataMap[key];
            if (!existing) {
                dataMap[key] = d;
            } else {
                // Merge: keep whichever entry has more data, or combine them
                dataMap[key] = {
                    ...existing,
                    ...d,
                    // Prefer non-null values from either entry
                    calorieIntake: d.calorieIntake ?? existing.calorieIntake,
                    value: d.value ?? existing.value,
                    googleFitTDEE: d.googleFitTDEE ?? existing.googleFitTDEE,
                    bfPercent: d.bfPercent ?? existing.bfPercent,
                    protein: d.protein ?? existing.protein,
                    carbs: d.carbs ?? existing.carbs,
                    fat: d.fat ?? existing.fat,
                    sma: d.sma ?? existing.sma,
                    ema: d.ema ?? existing.ema,
                    isOutlier: d.isOutlier || existing.isOutlier,
                    netBalance: d.netBalance ?? existing.netBalance,
                };
            }
        });
        return dataMap;
    },

    _getDayClass(calories) {
        if (calories == null) return 'no-data';
        const diff = calories - this._targetCalories;
        const pct = (diff / this._targetCalories) * 100;

        if (pct <= -15) return 'very-low';
        if (pct <= -5) return 'low';
        if (pct <= 5) return 'on-target';
        if (pct <= 15) return 'high';
        return 'very-high';
    },

    _renderCalendar(dataMap) {
        if (!this._container) return;

        const year = this._currentYear;
        const month = this._currentMonth;
        const firstDay = new Date(year, month, 1);
        const lastDay = new Date(year, month + 1, 0);
        const daysInMonth = lastDay.getDate();
        const startDayOfWeek = firstDay.getDay();

        const monthNames = ['January', 'February', 'March', 'April', 'May', 'June',
            'July', 'August', 'September', 'October', 'November', 'December'];

        let calendarHtml = `
      <div class="heatmap-header">
        <button class="nav-btn" id="prev-month">◀</button>
        <span class="month-title">${monthNames[month]} ${year}</span>
        <button class="nav-btn" id="next-month">▶</button>
      </div>
      <div class="heatmap-legend">
        <span class="legend-item very-low">Very Low</span>
        <span class="legend-item low">Low</span>
        <span class="legend-item on-target">On Target</span>
        <span class="legend-item high">High</span>
        <span class="legend-item very-high">Very High</span>
      </div>
      <div class="heatmap-grid">
        <div class="day-header">Sun</div>
        <div class="day-header">Mon</div>
        <div class="day-header">Tue</div>
        <div class="day-header">Wed</div>
        <div class="day-header">Thu</div>
        <div class="day-header">Fri</div>
        <div class="day-header">Sat</div>
    `;

        // Empty cells for days before month starts
        for (let i = 0; i < startDayOfWeek; i++) {
            calendarHtml += `<div class="day-cell empty"></div>`;
        }

        // Render each day
        for (let day = 1; day <= daysInMonth; day++) {
            const key = `${year}-${month}-${day}`;
            const dayData = dataMap[key];
            const calories = dayData?.calorieIntake;
            const weight = dayData?.value;
            const isOutlier = dayData?.isOutlier;
            const dayClass = this._getDayClass(calories);

            const hasWeight = weight != null;
            const hasCals = calories != null && calories > 0;

            calendarHtml += `
        <div class="day-cell ${dayClass}" data-date="${key}" tabindex="0"
             title="${calories ? calories + ' kcal' : 'No calorie data'}${weight ? ' | ' + weight.toFixed(1) + ' kg' : ' | No weight data'}">
          <span class="day-num">${day}</span>
          ${calories ? `<span class="day-cal">${Math.round(calories)}</span>` : ''}
          <div class="day-health-markers">
            ${!hasWeight ? '<span class="marker missing-weight" title="Missing weight entry">⚖️</span>' : ''}
            ${!hasCals ? '<span class="marker missing-cal" title="Missing calorie log">🥗</span>' : ''}
            ${isOutlier ? '<span class="marker outlier" title="Outlier detected">⭐</span>' : ''}
          </div>
        </div>
      `;
        }

        calendarHtml += `</div>`;

        // Day detail panel
        calendarHtml += `<div id="day-detail" class="day-detail hidden"></div>`;

        this._container.innerHTML = calendarHtml;

        // Event listeners
        this._container.querySelector('#prev-month')?.addEventListener('click', () => {
            this._currentMonth--;
            if (this._currentMonth < 0) {
                this._currentMonth = 11;
                this._currentYear--;
            }
            this._render();
        });

        this._container.querySelector('#next-month')?.addEventListener('click', () => {
            this._currentMonth++;
            if (this._currentMonth > 11) {
                this._currentMonth = 0;
                this._currentYear++;
            }
            this._render();
        });

        // Click on day
        this._container.querySelectorAll('.day-cell:not(.empty)').forEach(cell => {
            cell.addEventListener('click', (e) => {
                const dateKey = e.currentTarget.dataset.date;
                const dayData = dataMap[dateKey];
                this._showDayDetail(dayData, dateKey);
            });
            bindCrossWidgetHoverDate(cell, () => {
                const [hoverYear, hoverMonth, hoverDay] = cell.dataset.date.split('-').map(Number);
                return new Date(hoverYear, hoverMonth, hoverDay);
            }, { snapToLogged: false });
        });
    },

    _showDayDetail(dayData, dateKey) {
        const detailEl = this._container.querySelector('#day-detail');
        if (!detailEl) return;

        if (!dayData) {
            detailEl.innerHTML = '<p class="empty-detail">No data recorded for this day.</p>';
        } else {
            const [y, m, d] = dateKey.split('-').map(Number);
            const dateStr = `${d}/${m + 1}/${y}`;
            const isOutlier = dayData.isOutlier;
            const hasCals = dayData.calorieIntake > 0;
            const hasWeight = dayData.value != null;
            const outlierExplanation = isOutlier ? explainOutlier(dayData, this._getAvgCalories()) : null;
            const deviationKg = dayData.value != null && dayData.sma != null
                ? Math.abs(dayData.value - dayData.sma).toFixed(2)
                : null;

            detailEl.innerHTML = `
        <div class="detail-header">${dateStr}
          <button class="btn-focus-week" data-datekey="${dateKey}" title="Focus main chart on this week">Focus week</button>
        </div>
        <div class="detail-stats">
          <div class="detail-stat">
            <span class="label">Weight</span>
            <span class="value">${hasWeight ? dayData.value.toFixed(1) + ' kg' : '<span class="missing">Missing</span>'}</span>
          </div>
          <div class="detail-stat">
            <span class="label">Calories</span>
            <span class="value">${hasCals ? dayData.calorieIntake + ' kcal' : '<span class="missing">Missing</span>'}</span>
          </div>
          ${hasCals ? `
          <div class="detail-stat">
            <span class="label">Net Balance</span>
            <span class="value ${dayData.calorieIntake > this._targetCalories ? 'over' : 'under'}">
              ${(dayData.calorieIntake - this._targetCalories > 0 ? '+' : '') +
                    Math.round(dayData.calorieIntake - this._targetCalories)} kcal
            </span>
          </div>` : ''}
        </div>
        <div class="day-health-status">
            ${isOutlier ? `
                <div class="health-alert outlier-explanation">
                    <strong>⭐ Outlier</strong>
                    <div>${outlierExplanation?.narrative || 'Statistical anomaly detected.'}</div>
                    <div class="outlier-diagnostics">
                        ${deviationKg ? `<span class="outlier-chip">Deviation ${deviationKg} kg</span>` : ''}
                        ${dayData.outlierThresholdKg != null ? `<span class="outlier-chip">Threshold ${dayData.outlierThresholdKg.toFixed(2)} kg</span>` : ''}
                        ${dayData.anomalyScore != null ? `<span class="outlier-chip">Score ${dayData.anomalyScore.toFixed(2)}x</span>` : ''}
                        ${outlierExplanation?.severity ? `<span class="outlier-chip severity-${outlierExplanation.severity}">${outlierExplanation.severity}</span>` : ''}
                    </div>
                </div>
            ` : ''}
            ${!hasWeight ? '<div class="health-alert missing">⚠️ No weight recorded for this day.</div>' : ''}
            ${!hasCals ? '<div class="health-alert missing">⚠️ No calorie log for this day.</div>' : ''}
            ${hasWeight && hasCals && !isOutlier ? '<div class="health-alert good">✅ All data present and consistent.</div>' : ''}
        </div>
      `;
        }
        detailEl.classList.remove('hidden');

        // Bind the "Focus week" button
        detailEl.querySelector('.btn-focus-week')?.addEventListener('click', (e) => {
            const key = e.currentTarget.dataset.datekey;
            if (!key) return;
            const [y, m, d] = key.split('-').map(Number);
            const dayDate = new Date(y, m, d);
            const start = new Date(dayDate); start.setDate(start.getDate() - 3);
            const end   = new Date(dayDate); end.setDate(end.getDate() + 3);
            setAnalysisRangeAndSyncChart(start, end);
            // Scroll to chart
            document.getElementById('chart-section')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
        });
    },

    _renderNoData() {
        if (!this._container) return;
        this._container.innerHTML = `
      <div class="widget-empty-state">
        <div class="empty-icon">📊</div>
        <div class="empty-title">Need more data</div>
        <div class="empty-desc">At least 7 days of calorie data are required to generate the heatmap.</div>
      </div>
    `;
    },

    _getAvgCalories() {
        const state = StateManager.getState();
        const data = Selectors.selectProcessedData(state) || [];
        const recent = data.slice(-30).filter(d => d.calorieIntake != null && d.calorieIntake > 0);
        if (recent.length === 0) return null;
        return recent.reduce((s, d) => s + d.calorieIntake, 0) / recent.length;
    }
};
